export class EcoOneVisualCard extends LitElement {
  @property({ attribute: false }) public hass!: Hass;
  @state() private _config!: EcoOneVisualCardConfig;
  @state() private _svgContent: string = "";

  private _ids!: EcoOneSvgIds;
  private _entities!: EcoOneEntities;

  // Animation state
  private _rafId: number | null = null;
  private _fanAngle = 0;
  private _lastTimestamp = 0;
  private _animating = false;

  // ResizeObserver
  private _resizeObserver: ResizeObserver | null = null;
  private _imgWidth = 0;
  private _imgHeight = 0;

  /* ── HA card API ────────────────────────────────────────────── */

  public static getStubConfig(): Partial<EcoOneVisualCardConfig> {
    return {
      image: "/local/ecoone-outdoor.png",
      entities: { ...DEFAULT_ENTITIES },
    };
  }

  public setConfig(config: EcoOneVisualCardConfig): void {
    if (!config.image && !config.preview) {
      throw new Error("ecoone-visual-card: 'image' is required");
    }
    this._config = {
      aspect_ratio: "auto",
      ...config,
      entities: { ...DEFAULT_ENTITIES, ...config.entities },
    };
    this._ids = { ...DEFAULT_SVG_IDS, ...config.svg_ids };
    this._entities = this._config.entities;

    this._loadSvg();
  }

  public getCardSize(): number {
    return 6;
  }

  /* ── SVG loading ────────────────────────────────────────────── */

  private async _loadSvg(): Promise<void> {
    const svgCfg = this._config.svg;
    if (svgCfg?.inline_svg) {
      this._svgContent = svgCfg.inline_svg;
    } else if (svgCfg?.svg_url) {
      try {
        const resp = await fetch(svgCfg.svg_url);
        if (resp.ok) {
          this._svgContent = await resp.text();
        } else {
          this._svgContent = PLACEHOLDER_SVG;
        }
      } catch {
        this._svgContent = PLACEHOLDER_SVG;
      }
    } else {
      this._svgContent = PLACEHOLDER_SVG;
    }
    this.requestUpdate();
  }

  /* ── Entity helpers ─────────────────────────────────────────── */

  private _entityState(entityId: string | undefined): string | null {
    if (!entityId) return null;
    if (this._config.preview) return this._previewState(entityId);
    const obj = this.hass?.states?.[entityId];
    if (!obj) return null;
    const s = obj.state;
    if (s === "unavailable" || s === "unknown") return null;
    return s;
  }

  private _previewState(entityId: string): string | null {
    if (entityId.includes("fault")) return "off";
    if (entityId.includes("supply")) return "Supplying Hot Water";
    if (entityId.includes("heating")) return "Heating";
    if (entityId.includes("operation")) return "On";
    if (entityId.includes("tank_capacity")) return "70";
    if (entityId.includes("remaining")) return "88";
    if (entityId.includes("cumulative")) return "852.36";
    return null;
  }

  private _numericState(entityId: string | undefined): number | null {
    const s = this._entityState(entityId);
    if (s === null) return null;
    const n = parseFloat(s);
    return Number.isFinite(n) ? n : null;
  }

  /* ── Derived states ─────────────────────────────────────────── */

  private get _isOperating(): boolean {
    const s = this._entityState(this._entities.operation_status);
    return s !== null && s !== "Off" && s !== "Standby";
  }

  private get _isHeating(): boolean {
    return this._isOperating &&
      this._entityState(this._entities.heating_status) === "Heating";
  }

  private get _isSupplying(): boolean {
    return this._entityState(this._entities.supply_status) === "Supplying Hot Water";
  }

  private get _hasFault(): boolean {
    return this._entityState(this._entities.fault) === "on";
  }

  private get _tankPercent(): { physical: number; equivalent: number } | null {
    const cap = this._numericState(this._entities.tank_capacity_l);
    const rem = this._numericState(this._entities.hot_water_remaining_l);
    if (cap === null || rem === null || cap <= 0) return null;
    return {
      physical: Math.max(0, Math.min(1, rem / cap)),
      equivalent: rem / cap,
    };
  }

  private get _hasScheduleActive(): boolean {
    const s = this._entityState(this._entities.schedule);
    if (!s) return false;
    try {
      const parsed = typeof s === "string" ? JSON.parse(s) : s;
      const start = parsed.start_time ?? parsed.startTime ?? "0:00";
      const end = parsed.end_time ?? parsed.endTime ?? "0:00";
      return !(start === "0:00" && end === "0:00");
    } catch {
      return false;
    }
  }

  private get _needsAnimation(): boolean {
    return this._isOperating && this._isHeating;
  }

  /* ── Lifecycle ──────────────────────────────────────────────── */

  connectedCallback(): void {
    super.connectedCallback();
    this._startAnimationIfNeeded();
  }

  disconnectedCallback(): void {
    super.disconnectedCallback();
    this._stopAnimation();
    this._resizeObserver?.disconnect();
    this._resizeObserver = null;
  }

  updated(changedProps: PropertyValues): void {
    super.updated(changedProps);

    if (changedProps.has("hass") || changedProps.has("_config")) {
      if (this._needsAnimation && !this._animating) {
        this._startAnimationIfNeeded();
      } else if (!this._needsAnimation && this._animating) {
        this._stopAnimation();
      }
    }

    this._setupResizeObserver();
    this._applySvgState();
  }

  /* ── ResizeObserver ─────────────────────────────────────────── */

  private _setupResizeObserver(): void {
    if (this._resizeObserver) return;
    const img = this.shadowRoot?.querySelector(".bg-image") as HTMLImageElement | null;
    if (!img) return;

    this._resizeObserver = new ResizeObserver((entries) => {
      for (const entry of entries) {
        const { width, height } = entry.contentRect;
        if (width !== this._imgWidth || height !== this._imgHeight) {
          this._imgWidth = width;
          this._imgHeight = height;
          this._syncOverlaySize();
        }
      }
    });
    this._resizeObserver.observe(img);

    if (img.complete && img.naturalWidth) {
      this._imgWidth = img.offsetWidth;
      this._imgHeight = img.offsetHeight;
      this._syncOverlaySize();
    }
  }

  private _syncOverlaySize(): void {
    const overlay = this.shadowRoot?.querySelector(".svg-overlay") as HTMLElement | null;
    if (!overlay || !this._imgWidth) return;
    overlay.style.width = `${this._imgWidth}px`;
    overlay.style.height = `${this._imgHeight}px`;
  }

  /* ── Animation loop ─────────────────────────────────────────── */

  private _startAnimationIfNeeded(): void {
    if (this._animating) return;
    this._animating = true;
    this._lastTimestamp = 0;
    this._tick(0);
  }

  private _stopAnimation(): void {
    this._animating = false;
    if (this._rafId !== null) {
      cancelAnimationFrame(this._rafId);
      this._rafId = null;
    }
  }

  private _tick = (timestamp: number): void => {
    if (!this._animating) return;

    const dt = this._lastTimestamp ? timestamp - this._lastTimestamp : 16;
    this._lastTimestamp = timestamp;

    if (this._isHeating) {
      this._fanAngle = (this._fanAngle + (360 * dt) / FAN_PERIOD_MS) % 360;
    }

    this._applySvgState();

    this._rafId = requestAnimationFrame(this._tick);
  };

  /* ── Apply animation state to SVG elements ──────────────────── */

  private _applySvgState(): void {
    const root = this.shadowRoot;
    if (!root) return;

    const svgContainer = root.querySelector(".svg-overlay") as HTMLElement | null;
    if (!svgContainer) return;

    // Fan rotation — spin from visual center using fill-box
    const fan = svgContainer.querySelector(`#${CSS.escape(this._ids.fanGroupId)}`) as SVGElement | null;
    if (fan) {
      fan.style.transformBox = "fill-box";
      fan.style.transformOrigin = "center";
      if (this._isHeating) {
        fan.style.transform = `rotate(${this._fanAngle}deg)`;
        fan.style.opacity = "0.85";
        fan.style.filter = "drop-shadow(0 0 6px rgba(255,180,80,0.3))";
      } else {
        fan.style.transform = "rotate(0deg)";
        fan.style.opacity = "0.3";
        fan.style.filter = "none";
      }
    }

    // Tank fill
    this._applyTankFill(svgContainer);

    // Heating indicator (SVG flame + text)
    const heatInd = svgContainer.querySelector("#HeatingIndicator") as SVGElement | null;
    if (heatInd) {
      heatInd.style.transition = "opacity 500ms ease";
      heatInd.style.opacity = this._isHeating ? "1" : "0";
    }

    // Not-heating indicator (inverse of heating)
    const notHeatInd = svgContainer.querySelector("#NotHeatingIndicator") as SVGElement | null;
    if (notHeatInd) {
      notHeatInd.style.transition = "opacity 500ms ease";
      notHeatInd.style.opacity = !this._isHeating && this._isOperating ? "1" : "0";
    }

    // Supply indicator (SVG thermometer + text)
    const supplyInd = svgContainer.querySelector("#SupplyIndicator") as SVGElement | null;
    if (supplyInd) {
      if (this._isSupplying && this._isOperating) {
        supplyInd.style.animation = "supply-pulse 1s ease-in-out infinite";
        supplyInd.style.opacity = "";
      } else {
        supplyInd.style.animation = "none";
        supplyInd.style.opacity = "0";
      }
    }

    // Fault indicator (SVG warning badge) — flashes when fault is active
    const faultInd = svgContainer.querySelector("#FaultIndicator") as SVGElement | null;
    if (faultInd) {
      if (this._hasFault) {
        faultInd.style.animation = "fault-svg-flash 2s ease-in-out infinite";
        faultInd.style.opacity = "";
      } else {
        faultInd.style.animation = "none";
        faultInd.style.opacity = "0";
      }
    }

    // Schedule dotted outline
    const tank = svgContainer.querySelector(`#${CSS.escape(this._ids.tankOutlineId)}`) as SVGElement | null;
    if (tank) {
      const outline = tank.querySelector("rect, path, circle, ellipse") as SVGElement | null;
      if (outline && this._hasScheduleActive) {
        outline.setAttribute("stroke-dasharray", "4 3");
        outline.setAttribute("stroke", "rgba(180,220,255,0.35)");
      } else if (outline) {
        outline.removeAttribute("stroke-dasharray");
      }
    }
  }

  /* ── Tank fill algorithm ────────────────────────────────────── */

  /**
   * Hot water rises to the top of the tank, so we clip from the BOTTOM.
   * inset(0 0 X% 0) hides X% from the bottom, revealing the top portion.
   *
   *   100% fill → inset(0 0 0% 0)   → full orange
   *    50% fill → inset(0 0 50% 0)  → top half orange, bottom half blue
   *     0% fill → inset(0 0 100% 0) → all blue (no orange)
   */
  private _applyTankFill(container: HTMLElement): void {
    const hotFill = container.querySelector(`#${CSS.escape(this._ids.tankFillHotId)}`) as SVGElement | null;
    if (!hotFill) return;

    const tank = this._tankPercent;

    if (tank === null) {
      hotFill.style.clipPath = "inset(0 0 50% 0)";
      hotFill.style.transition = "clip-path 600ms ease";
      hotFill.style.filter = "saturate(0.3) opacity(0.5)";
      return;
    }

    const insetBottom = ((1 - tank.physical) * 100).toFixed(1);
    hotFill.style.clipPath = `inset(0 0 ${insetBottom}% 0)`;
    hotFill.style.transition = "clip-path 600ms ease";

    if (tank.equivalent > 1) {
      hotFill.style.filter = "drop-shadow(0 0 10px rgba(255,140,50,0.35)) brightness(1.1)";
    } else {
      hotFill.style.filter = "none";
    }
  }

  /* ── Styles ─────────────────────────────────────────────────── */

  static styles = css`
    :host {
      display: block;
    }

    .card-container {
      position: relative;
      width: 100%;
      border-radius: 12px;
      overflow: hidden;
      background: #111;
      transition: filter 800ms ease;
    }

    .card-container.inactive {
      filter: saturate(0.45) brightness(0.85);
    }

    .card-container.fault {
      filter: saturate(0.8);
    }

    .bg-image {
      display: block;
      width: 100%;
      height: auto;
    }

    .svg-overlay {
      position: absolute;
      top: 0;
      left: 0;
      pointer-events: none;
      z-index: 2;
    }

    .svg-overlay svg {
      width: 100%;
      height: 100%;
      display: block;
    }

    /* Cinematic vignette */
    .vignette {
      position: absolute;
      inset: 0;
      pointer-events: none;
      z-index: 3;
      background: radial-gradient(ellipse at center, transparent 55%, rgba(0, 0, 0, 0.45) 100%);
      transition: opacity 800ms ease;
    }

    /* Warm lighting overlay when heating */
    .warm-glow {
      position: absolute;
      inset: 0;
      pointer-events: none;
      z-index: 3;
      background: radial-gradient(ellipse at 65% 50%, rgba(255, 150, 50, 0.06) 0%, transparent 70%);
      opacity: 0;
      transition: opacity 800ms ease;
    }

    .warm-glow.active {
      opacity: 1;
    }

    /* Fault warning overlay — mild red flash over entire image */
    .fault-overlay {
      position: absolute;
      inset: 0;
      pointer-events: none;
      z-index: 3;
      background: rgba(200, 30, 30, 0.5);
      opacity: 0;
    }

    .fault-overlay.active {
      animation: fault-flash 2s ease-in-out infinite;
    }

    @keyframes fault-flash {
      0%, 100% { opacity: 0; }
      50% { opacity: 1; }
    }

    /* Fault SVG indicator flash (applied via JS) */
    @keyframes fault-svg-flash {
      0%, 100% { opacity: 0.4; }
      50% { opacity: 1; }
    }

    /* Supply SVG indicator pulse (applied via JS) */
    @keyframes supply-pulse {
      0%, 100% { opacity: 0.4; }
      50% { opacity: 1; }
    }

  `;

  /* ── Render ─────────────────────────────────────────────────── */

  render() {
    if (!this._config) {
      return html`<ha-card><div class="card-container">Loading…</div></ha-card>`;
    }

    const inactive = !this._isOperating;
    const heating = this._isHeating;
    const fault = this._hasFault;

    const containerClasses = [
      "card-container",
      inactive ? "inactive" : "",
      fault && !inactive ? "fault" : "",
    ].filter(Boolean).join(" ");

    const aspectStyle = this._computeAspectStyle();

    return html`
      <ha-card>
        <div class="${containerClasses}" style="${aspectStyle}">
          ${this._config.image
            ? html`<img
                class="bg-image"
                src="${this._config.image}"
                alt="Eco One"
                @load="${this._onImageLoad}"
              />`
            : nothing}

          <div class="svg-overlay" .innerHTML="${this._svgContent}"></div>

          <div class="vignette"></div>
          <div class="warm-glow ${heating ? "active" : ""}"></div>
          <div class="fault-overlay ${fault ? "active" : ""}"></div>

        </div>
      </ha-card>
    `;
  }

  private _onImageLoad = (): void => {
    const img = this.shadowRoot?.querySelector(".bg-image") as HTMLImageElement | null;
    if (!img) return;
    this._imgWidth = img.offsetWidth;
    this._imgHeight = img.offsetHeight;
    this._syncOverlaySize();
    this._setupResizeObserver();
    this._applySvgState();
  };

  private _computeAspectStyle(): string {
    const ratio = this._config.aspect_ratio;
    if (!ratio || ratio === "auto") return "";
    const parts = ratio.split(":");
    if (parts.length === 2) {
      const w = parseFloat(parts[0]);
      const h = parseFloat(parts[1]);
      if (w > 0 && h > 0) {
        return `aspect-ratio: ${w} / ${h};`;
      }
    }
    return "";
  }
}

/* ================================================================
   Registration
   ================================================================ */

declare global {
  interface HTMLElementTagNameMap {
    "ecoone-visual-card": EcoOneVisualCard;
  }
  interface Window {
    customCards?: Array<{ type: string; name: string; description: string }>;
  }
}

if (!customElements.get("ecoone-visual-card")) {
  customElements.define("ecoone-visual-card", EcoOneVisualCard);
}

if (typeof window !== "undefined") {
  window.customCards = window.customCards || [];
  if (!window.customCards.some((c) => c.type === "ecoone-visual-card")) {
    window.customCards.push({
      type: "ecoone-visual-card",
      name: "Eco One Visual",
      description: "Premium minimal Eco One heat pump + tank visualization with SVG overlays",
    });
  }
}

if (import.meta.hot) {
  import.meta.hot.accept();
  import.meta.hot.invalidate();
}
